"use client";

import { useTranslations } from "next-intl";
import { useSession } from "next-auth/react";
import { motion } from "framer-motion";
import { GraduationCap, BookOpen, Target, Sparkles, LayoutDashboard, ArrowRight } from "lucide-react";
import { Link } from "@/navigation";

export default function StudentDashboard() {
    const t = useTranslations("Navigation");
    const { data: session } = useSession();

    return (
        <div className="min-h-screen pt-32 px-6">
            <div className="max-w-7xl mx-auto space-y-12">
                <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                    <div className="space-y-4">
                        <div className="inline-flex items-center gap-2 px-4 py-2 bg-blue-50 rounded-full border border-blue-100">
                            <Sparkles className="w-4 h-4 text-blue-600" />
                            <span className="text-xs font-black text-blue-600 uppercase tracking-widest">Student Portal</span>
                        </div>
                        <h1 className="text-4xl md:text-6xl font-black text-slate-800 tracking-tight">
                            Welcome back, <span className="text-blue-600">{session?.user?.name || "Learner"}</span>
                        </h1>
                    </div>
                </header>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-2 space-y-8">
                        {/* Recent Activity / Subjects */}
                        <div className="glass-panel p-8 space-y-8">
                            <div className="flex items-center justify-between">
                                <h2 className="text-2xl font-black text-slate-800 tracking-tight flex items-center gap-3">
                                    <BookOpen className="w-6 h-6 text-blue-600" />
                                    Your Learning Paths
                                </h2>
                            </div>

                            <div className="bg-slate-50 border border-slate-100 rounded-3xl p-12 text-center space-y-6">
                                <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto shadow-sm">
                                    <Target className="w-8 h-8 text-slate-300" />
                                </div>
                                <div className="space-y-2">
                                    <h3 className="text-xl font-bold text-slate-800">No active paths yet</h3>
                                    <p className="text-slate-500 font-medium">Complete a diagnostic quiz to generate your first AI-powered roadmap.</p>
                                </div>
                                <Link
                                    href="/diagnostic"
                                    className="inline-flex items-center gap-2 px-8 py-4 bg-slate-900 text-white rounded-2xl font-black transition-all hover:bg-slate-800"
                                >
                                    Take Diagnostic
                                    <ArrowRight className="w-5 h-5" />
                                </Link>
                            </div>
                        </div>
                    </div>

                    <div className="space-y-8">
                        {/* Career Insights Shortcut */}
                        <div className="glass-panel p-8 space-y-6 bg-gradient-to-br from-indigo-600 to-blue-700 text-white border-none shadow-xl shadow-blue-500/10">
                            <div className="w-12 h-12 bg-white/10 rounded-2xl flex items-center justify-center border border-white/10">
                                <GraduationCap className="w-6 h-6 text-white" />
                            </div>
                            <div className="space-y-2">
                                <h3 className="text-2xl font-black tracking-tight">Major Predictor</h3>
                                <p className="text-blue-100 font-medium leading-relaxed">
                                    Let AI analyze your overall performance to discover the best university major for you.
                                </p>
                            </div>
                            <Link
                                href="/predictor"
                                className="w-full flex items-center justify-center gap-2 py-4 bg-white text-blue-600 rounded-2xl font-black transition-all hover:bg-blue-50"
                            >
                                Open Predictor
                            </Link>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}
